    47→public class Asg {
    48→
    49→  private static final Logger logger = Logger.getLogger(Asg.class.getName());
    50→
    51→  static {
    52→    try {
    53→      InputStream stream = Asg.class.getResourceAsStream("logging.properties");
    54→      LogManager.getLogManager().readConfiguration(stream);
    55→    } catch (Exception e) {
    56→      throw new RuntimeException(e);
    57→    }
    58→    SimpleModule simpleModule = new SimpleModule().addSerializer(new JsonNodeExampleSerializer());
    59→    Json.mapper().registerModule(simpleModule);
    60→  }
    61→
    62→  private final YamlConfig config;
    63→
    64→  private Asg(YamlConfig config) {
    65→    this.config = Objects.requireNonNull(config);
    66→  }
    67→
    68→  void generate() {
    69→    logger.info("Preparing ontology and generating api");
    70→    ensureAPIOutputDirExists();
    71→    saveEffectiveConfig();
    72→    generateOpenApiSpecs(addSecurityScheme(addExamples(OntologyMapper.map(config))));
    73→  }
    74→
    75→  void flattenOnly() {
    76→    logger.info("Option --no-generate selected: will output prepared ontology from given config");
    77→    ensureAPIOutputDirExists();
    78→    saveEffectiveConfig();
    79→    new OntologyMapper(config); // loads and outputs ontology
    80→  }
    81→
    82→  private void ensureAPIOutputDirExists() {
    83→    Path outputDir = config.getApiOutputDir();
    84→    if (!outputDir.toFile().exists()) {
    85→      boolean mkdirs = outputDir.toFile().mkdirs();
    86→      if (!mkdirs) {
    87→        throw new RuntimeException("Failed to create output directory: " + outputDir);
    88→      }
    89→    }
    90→  }
    91→
    92→  private void saveEffectiveConfig() {
    93→    try {
    94→      Yaml.mapper().writeValue(config.getApiOutputDir().resolve("effective-config.yaml").toFile(), config);
    95→    } catch (IOException e) {
    96→      throw new RuntimeException(e);
    97→    }
    98→
    99→  }
   100→
   101→  public static void main(String[] args) {
   102→    try {
   103→      CommandLine commandLine = parseCommandLine(args);
   104→      YamlConfig config = Config.load(Path.of(commandLine.getOptionValue("config")));
   105→
   106→      // if output dir on command line apply to config
   107→      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
   108→          .map(Path::of)
   109→          .map(Path::toAbsolutePath)
   110→          .ifPresent(config::setOutputDir);
   111→      if (commandLine.hasOption("ontology-file")) {
   112→        // ontology provided on command line - override config
   113→        String ontologyFile = commandLine.getOptionValue("ontology-file");
   114→        config.setOntologies(List.of(ontologyFile.matches("^\\w+://") ? new URI(ontologyFile)
   115→            : Path.of(ontologyFile).toAbsolutePath().toUri()));
   116→      }
   117→      // if output dir on command line apply to config
   118→      Optional.ofNullable(commandLine.getOptionValue("output-dir"))
   119→          .map(Path::of)
   120→          .map(Path::toAbsolutePath)
   121→          .ifPresent(config::setOutputDir);
   122→
   123→      Asg asg = new Asg(config);
   124→      if (commandLine.hasOption("no-generate")) {
   125→        asg.flattenOnly();
   126→      } else {
   127→        asg.generate();
   128→      }
   129→    } catch (Exception e) {
   130→      logger.severe(e.getMessage());
   131→      throw new RuntimeException(e);
   132→    }
   133→  }
   134→
   135→  private static CommandLine parseCommandLine(String[] args) {
   136→    // obtain the options to pass configuration
   137→    Options options = new Options();
   138→    Option config = new Option("c", "config", true, "configuration file path");
   139→    config.setRequired(true);
   140→    options.addOption(config);
   141→    options.addOption(
   142→        new Option("f", "ontology-file", true, "override the ontology file specified in config"));
   143→    options.addOption(
   144→        new Option("o", "output-dir", true, "override the output directpry specified in config"));
   145→    options.addOption(new Option("G", "no-generate", false,
   146→        "stop after loading ontology and output flattened version"));
   147→
   148→    try {
   149→      return new DefaultParser().parse(options, args);
   150→    } catch (ParseException e) {
   151→      new HelpFormatter().printHelp("Asg", options);
   152→      throw new RuntimeException(e);
   153→    }
   154→
   155→  }
   156→
   157→  private OpenAPI addExamples(OpenAPI openApiBase) {
   158→    openApiBase.getPaths().values()
   159→        .forEach(pathItem -> Optional.ofNullable(pathItem.readOperationsMap().get(PathItem.HttpMethod.GET))
   160→            .flatMap(operation -> Optional.ofNullable(operation.getResponses().get("200"))
   161→                .flatMap(apiResponse -> Optional.ofNullable(apiResponse.getContent())
   162→                    .map(content -> content.get("application/json")))).ifPresent(mediaType -> {
   163→              Example example = ExampleBuilder.fromSchema(mediaType.getSchema(), openApiBase.getComponents()
   164→                  .getSchemas());
   165→              mediaType.setExample(Json.mapper().valueToTree(example));
   166→            }));
   167→
   168→    return openApiBase;
   169→  }
   170→
   171→  /**
   172→   * Generate the security spec for the whole api by gathering all required scopes
   173→   *
   174→   * @param openAPIBase
   175→   * @return
   176→   */
   177→  private OpenAPI addSecurityScheme(OpenAPI openAPIBase) {
   178→    config.getOAuth2SecuritySchemeName().ifPresentOrElse(oauthSchemaName -> {
   179→      Set<String> allScopes = openAPIBase.getPaths().values().stream()
   180→          .flatMap(pathItem -> pathItem.readOperations().stream())
   181→          .flatMap(operation -> Optional.ofNullable(operation.getSecurity()).stream()
   182→              .flatMap(securityRequirements -> securityRequirements.stream()
   183→                  .filter(securityRequirement -> securityRequirement.containsKey(oauthSchemaName))
   184→                  .flatMap(securityRequirement -> securityRequirement.values().stream()))).flatMap(Collection::stream)
   185→          .collect(Collectors.toUnmodifiableSet());
   186→
   187→      SecurityScheme securityScheme = Optional.ofNullable(openAPIBase.getComponents().getSecuritySchemes())
   188→          .map(stringSecuritySchemeMap -> stringSecuritySchemeMap.get(oauthSchemaName)).orElseGet(SecurityScheme::new);
   189→      OAuthFlows flows = securityScheme.flows(Optional.ofNullable(securityScheme.getFlows()).orElseGet(OAuthFlows::new))
   190→          .getFlows();
   191→      OAuthFlow flow = flows.authorizationCode(Optional.ofNullable(flows.getAuthorizationCode())
   192→          .orElseGet(OAuthFlow::new)).getAuthorizationCode();
   193→      Scopes scopes = flow.scopes(Optional.ofNullable(flow.getScopes()).orElseGet(Scopes::new)).getScopes();
   194→      allScopes.stream().sorted()
   195→          .forEach(s -> {scopes.put(s, StringUtils.capitalize(StringUtils.replacePattern(s, "\\W", " ")));});
   196→      openAPIBase.schemaRequirement(oauthSchemaName, securityScheme);
   197→    }, () -> {
   198→      logger.warning("No oauth securitySchemeName or oauth securityScheme in template components - auth scopes will " +
   199→          "not be added");
   200→    });
   201→    return openAPIBase;
   202→  }
   203→
   204→  private void generateOpenApiSpecs(OpenAPI openApiBase) {
   205→    List.of(Pair.of(ObjectMapperFactory.createYaml31(), "yaml"), Pair.of(ObjectMapperFactory.createJson31(), "json"))
   206→        .forEach(mapperExtension -> {
   207→      ObjectMapper mapper = mapperExtension.getLeft();
   208→          mapper.setSerializationInclusion(Include.NON_NULL);
   209→      mapper.enable(SerializationFeature.INDENT_OUTPUT);
   210→      File outputFile = config.getApiOutputDir().resolve("openapi." + mapperExtension.getRight()).toFile();
   211→      try {
   212→        mapper.writeValue(outputFile, openApiBase);
   213→      } catch (IOException e) {
   214→        throw new RuntimeException(e);
   215→      }
   216→      SwaggerParseResult result = new OpenAPIParser().readLocation(outputFile.toURI()
   217→          .toString(), null, new ParseOptions());
   218→      List<String> messageList = result.getMessages();
   219→      if (messageList.isEmpty()) {
   220→        logger.info("Successfully generated and validated " + outputFile);
   221→
   222→      } else {
   223→        messageList.forEach(logger::severe);
   224→        throw new RuntimeException(
   225→            "Error(s) when validating the generated API specification: " + outputFile);
   226→      }
   227→    });
   228→  }
   229→
   230→}
