    11→public class TaxonomyPropertyMapper {
    12→
    13→  private final String name;
    14→  private final String description;
    15→  private final List<String> ref;
    16→
    17→  public boolean isRequired() {
    18→    return isRequired;
    19→  }
    20→
    21→  private final boolean isRequired;
    22→  private final boolean isArray;
    23→  private final Set<RestrictionInfo> restrictions;
    24→  private final String label;
    25→
    26→  public TaxonomyPropertyMapper(MappingContext context, String propertyName, String description,
    27→      String label, List<String> ref, Set<RestrictionInfo> restrictions) {
    28→    this.name = propertyName;
    29→    this.description = description;
    30→    this.label = label;
    31→    this.ref = ref;
    32→    this.restrictions = restrictions;
    33→
    34→    // Compute array and required from restrictions
    35→    YamlConfig config = context.getConfig();
    36→    this.isArray =
    37→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    38→    this.isRequired = config.isEnforceRequiredness() &&
    39→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
    40→  }
    41→
    42→  public String getName() {
    43→    return name;
    44→  }
    45→
    46→  public Schema getTaxonomySchemaObject() {
    47→    return getComposedSchemaObject(this.ref);
    48→  }
    49→
    50→  private Schema getComposedSchemaObject(List<String> ref) {
    51→    StringSchema enumSchema = new StringSchema();
    52→    enumSchema.setDescription(this.description);
    53→    enumSchema.setEnum(ref);
    54→    if (isArray) {
    55→      // Is array of enums
    56→      ArraySchema arraySchema = new ArraySchema();
    57→      arraySchema.setName(this.name);
    58→      arraySchema.setTitle(this.label);
    59→      // NEW: Use typed restrictions (Phase 4) - correct OWL semantics
    60→      for (RestrictionInfo restriction : this.restrictions) {
    61→        restriction.applyToArraySchema(arraySchema);
    62→      }
    63→      arraySchema.setItems(enumSchema);
    64→      return arraySchema;
    65→    } else {
    66→      enumSchema.setName(this.name);
    67→      enumSchema.setTitle(this.label);
    68→      // is a single enum
    69→      return enumSchema;
    70→    }
    71→  }
    72→}
