    21→
    22→  private final Map<String, Schema<?>> schemaByRef = new ConcurrentSkipListMap<>(); // so we can safely computeIfAbsent
    23→  private final Set<String> computing = new HashSet<>();
    24→  private final String schemaLabel;
    25→
    26→  private final OWLClass apiRootClass;
    27→
    28→  private final Set<OWLClass> resourceClasses;
    29→
    30→  private final YamlConfig config;
    31→
    32→  public MappingContext(String defaultOntologyPrefixIRI, OWLOntology ontology, String schemaLabel,
    33→                        OWLClass apiRootClass, Set<OWLClass> resourceClasses, YamlConfig config) {
    34→    this.defaultOntologyPrefixIRI = defaultOntologyPrefixIRI;
    35→    this.ontology = ontology;
    36→    this.schemaLabel = schemaLabel;
    37→    this.apiRootClass = apiRootClass;
    38→    this.resourceClasses = Collections.unmodifiableSet(resourceClasses);
    39→    this.config = config;
    40→  }
