import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLDataMaxCardinality;
import org.semanticweb.owlapi.model.OWLDataMinCardinality;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLDataSomeValuesFrom;
import org.semanticweb.owlapi.model.OWLLiteral;
import org.semanticweb.owlapi.model.OWLObjectMaxCardinality;
import org.semanticweb.owlapi.model.OWLObjectMinCardinality;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLObjectSomeValuesFrom;

class RestrictionInfoTest {

  private OWLDataFactory df;
  private PropertyNameResolver nameResolver;

  @BeforeEach
  void setUp() {
    df = OWLManager.getOWLDataFactory();
    nameResolver = new PropertyNameResolver();
  }

  @Test
  void testSomeValuesFromCreation() {
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLObjectSomeValuesFrom restriction = df.getOWLObjectSomeValuesFrom(prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.SomeValuesFrom(restriction);

    assertNotNull(info.expression());
    assertTrue(info.filler().isPresent());
    assertEquals(rangeClass, info.filler().get());
  }

  @Test
  void testMinCardinalityImpliesRequired() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectMinCardinality restriction = df.getOWLObjectMinCardinality(1, prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.MinCardinality(restriction);

    assertTrue(info.impliesRequired());
    assertTrue(info.cardinality().isPresent());
    assertEquals(1, info.cardinality().getAsInt());
  }

  @Test
  void testMinCardinalityZeroDoesNotImplyRequired() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectMinCardinality restriction = df.getOWLObjectMinCardinality(0, prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.MinCardinality(restriction);

    assertFalse(info.impliesRequired());
  }

  @Test
  void testMaxCardinalityImpliesArray() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectMaxCardinality restriction = df.getOWLObjectMaxCardinality(5, prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.MaxCardinality(restriction);

    assertTrue(info.impliesArray());
    assertTrue(info.cardinality().isPresent());
    assertEquals(5, info.cardinality().getAsInt());
  }

  @Test
  void testMaxCardinalityOneDoesNotImplyArray() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectMaxCardinality restriction = df.getOWLObjectMaxCardinality(1, prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.MaxCardinality(restriction);

    assertFalse(info.impliesArray());
  }

  @Test
  void testGetRangeNamesFromSomeValuesFrom() {
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLObjectSomeValuesFrom restriction = df.getOWLObjectSomeValuesFrom(prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.SomeValuesFrom(restriction);
    List<String> rangeNames = info.getRangeNames(nameResolver);

    assertEquals(1, rangeNames.size());
    assertEquals("RangeClass", rangeNames.getFirst());
  }

  @Test
  void testGetRangeNamesFromDataRestriction() {
    OWLDataProperty prop = df.getOWLDataProperty(IRI.create("http://example.org/", "property"));
    OWLDataSomeValuesFrom restriction = df.getOWLDataSomeValuesFrom(prop,
        df.getStringOWLDatatype());

    RestrictionInfo info = new RestrictionInfo.DataSomeValuesFrom(restriction);
    List<String> rangeNames = info.getRangeNames(nameResolver);

    assertEquals(1, rangeNames.size());
    assertEquals("string", rangeNames.getFirst());
  }

  @Test
  void testDataMinCardinalityImpliesRequired() {
    OWLDataProperty prop = df.getOWLDataProperty(IRI.create("http://example.org/", "property"));
    OWLDataMinCardinality restriction = df.getOWLDataMinCardinality(1, prop,
        df.getStringOWLDatatype());

    RestrictionInfo info = new RestrictionInfo.DataMinCardinality(restriction);

    assertTrue(info.impliesRequired());
  }

  @Test
  void testDataMaxCardinalityImpliesArray() {
    OWLDataProperty prop = df.getOWLDataProperty(IRI.create("http://example.org/", "property"));
    OWLDataMaxCardinality restriction = df.getOWLDataMaxCardinality(3, prop,
        df.getStringOWLDatatype());

    RestrictionInfo info = new RestrictionInfo.DataMaxCardinality(restriction);

    assertTrue(info.impliesArray());
  }

  @Test
  void testGetEnumValuesFromDataOneOf() {
    OWLDataProperty prop = df.getOWLDataProperty(IRI.create("http://example.org/", "property"));
    OWLLiteral lit1 = df.getOWLLiteral("value1");
    OWLLiteral lit2 = df.getOWLLiteral("value2");
    OWLLiteral lit3 = df.getOWLLiteral("value3");

    RestrictionInfo.DataOneOf info = new RestrictionInfo.DataOneOf(
        df.getOWLDataOneOf(lit1, lit2, lit3));

    List<String> enumValues = info.getEnumValues();

    assertEquals(3, enumValues.size());
    assertTrue(enumValues.contains("value1"));
    assertTrue(enumValues.contains("value2"));
    assertTrue(enumValues.contains("value3"));
  }

  @Test
  void testFromObjectMinCardinality() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectMinCardinality restriction = df.getOWLObjectMinCardinality(1, prop, rangeClass);

    var result = RestrictionInfo.from(restriction);

    assertTrue(result.isPresent());
    assertInstanceOf(RestrictionInfo.MinCardinality.class, result.get());
  }

  @Test
  void testFromDataMaxCardinality() {
    OWLDataProperty prop = df.getOWLDataProperty(IRI.create("http://example.org/", "property"));
    OWLDataMaxCardinality restriction = df.getOWLDataMaxCardinality(5, prop,
        df.getStringOWLDatatype());

    var result = RestrictionInfo.from(restriction);

    assertTrue(result.isPresent());
    assertInstanceOf(RestrictionInfo.DataMaxCardinality.class, result.get());
  }

  @Test
  void testSomeValuesFromImpliesArray() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectSomeValuesFrom restriction = df.getOWLObjectSomeValuesFrom(prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.SomeValuesFrom(restriction);

    assertTrue(info.impliesArray());
  }

  @Test
  void testSomeValuesFromImpliesRequired() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectSomeValuesFrom restriction = df.getOWLObjectSomeValuesFrom(prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.SomeValuesFrom(restriction);

    assertTrue(info.impliesRequired());
  }

  @Test
  void testCardinalityDefaultEmpty() {
    OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create("http://example.org/", "property"));
    OWLClass rangeClass = df.getOWLClass(IRI.create("http://example.org/", "RangeClass"));
    OWLObjectSomeValuesFrom restriction = df.getOWLObjectSomeValuesFrom(prop, rangeClass);

    RestrictionInfo info = new RestrictionInfo.SomeValuesFrom(restriction);

    assertTrue(info.cardinality().isEmpty());
  }
}

