    @Test
    void testArrayCardinalityMovedFromItemsToArray() {
      OWLDataProperty prop = df.getOWLDataProperty("http://example.org/", "prop");
      RestrictionInfo.DataMinCardinality minCard = new RestrictionInfo.DataMinCardinality(
          df.getOWLDataMinCardinality(2, prop, df.getStringOWLDatatype()));
      RestrictionInfo.DataMaxCardinality maxCard = new RestrictionInfo.DataMaxCardinality(
          df.getOWLDataMaxCardinality(5, prop, df.getStringOWLDatatype()));

      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "testProp", "Test Property", "Description",
          null, Set.of(minCard, maxCard), Collections.emptyList(), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertInstanceOf(ArraySchema.class, schema);
      ArraySchema arraySchema = (ArraySchema) schema;
      assertEquals(2, arraySchema.getMinItems());
      assertEquals(5, arraySchema.getMaxItems());
      // Items schema should not have cardinality
      assertNull(arraySchema.getItems().getMinItems());
      assertNull(arraySchema.getItems().getMaxItems());
    }
  }

