  @Nested
  class EnumHandling {

    @Test
    void testDataOneOfCreatesEnumValues() {
      OWLLiteral lit1 = df.getOWLLiteral("value1");
      OWLLiteral lit2 = df.getOWLLiteral("value2");
      OWLLiteral lit3 = df.getOWLLiteral("value3");

      RestrictionInfo.DataOneOf restriction = new RestrictionInfo.DataOneOf(
          df.getOWLDataOneOf(lit1, lit2, lit3));

      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "testProp", "Test Property", "Description",
          null, Set.of(restriction), List.of("value1", "value2", "value3"), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertInstanceOf(StringSchema.class, schema);
      StringSchema stringSchema = (StringSchema) schema;
      assertNotNull(stringSchema.getEnum());
      assertEquals(3, stringSchema.getEnum().size());
      assertTrue(stringSchema.getEnum().contains("value1"));
      assertTrue(stringSchema.getEnum().contains("value2"));
      assertTrue(stringSchema.getEnum().contains("value3"));
    }

    @Test
    void testEnumValuesAreSorted() {
      OWLLiteral lit1 = df.getOWLLiteral("zebra");
      OWLLiteral lit2 = df.getOWLLiteral("apple");
      OWLLiteral lit3 = df.getOWLLiteral("mango");

      RestrictionInfo.DataOneOf restriction = new RestrictionInfo.DataOneOf(
          df.getOWLDataOneOf(lit1, lit2, lit3));

      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "testProp", "Test Property", "Description",
          null, Set.of(restriction), List.of("zebra", "apple", "mango"), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      StringSchema stringSchema = (StringSchema) schema;
      assertEquals("apple", stringSchema.getEnum().get(0));
      assertEquals("mango", stringSchema.getEnum().get(1));
      assertEquals("zebra", stringSchema.getEnum().get(2));
    }
  }

