  @BeforeEach
  void setUp() {
    df = OWLManager.getOWLDataFactory();
    config = new YamlConfig();
    configWithRequiredness = new YamlConfig() {
      @Override
      public boolean isEnforceRequiredness() {
        return true;
      }
    };
  }

  @Nested
  class XsdDataTypeMapping {

    @Test
    void testStringType() {
      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "testProp", "Test Property", "Description",
          null, Collections.emptySet(), Collections.emptyList(), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertInstanceOf(StringSchema.class, schema);
      assertEquals("testProp", schema.getName());
      assertEquals("Test Property", schema.getTitle());
    }

    @Test
    void testIntegerType() {
