      assertInstanceOf(StringSchema.class, schema);
    }

    @Test
    void testUnsignedIntTypes() {
      for (String type : List.of("unsignedByte", "unsignedShort", "unsignedInt", "unsignedLong")) {
        DataPropertyMapper mapper = new DataPropertyMapper(
            config, "testProp", "Test", "Desc",
            null, Collections.emptySet(), Collections.emptyList(), List.of(type));

        Schema<?> schema = mapper.getSchemaByDataProperty();

        assertInstanceOf(IntegerSchema.class, schema, "Failed for type: " + type);
      }
