              df.getOWLClass("http://example.org/", "A"),
              df.getOWLClass("http://example.org/", "B")));

      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "testProp", "Test Property", "Description",
          null, Set.of(restriction), Collections.emptyList(), List.of("string", "integer"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertInstanceOf(ArraySchema.class, schema);
      ArraySchema arraySchema = (ArraySchema) schema;
      assertInstanceOf(ComposedSchema.class, arraySchema.getItems());
      ComposedSchema composedSchema = (ComposedSchema) arraySchema.getItems();
      assertNotNull(composedSchema.getAllOf());
      assertEquals(2, composedSchema.getAllOf().size());
    }
  }

  @Nested
  class SchemaMetadata {

    @Test
    void testSchemaNameSet() {
      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "propertyName", "Property Label", "Property Description",
          null, Collections.emptySet(), Collections.emptyList(), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertEquals("propertyName", schema.getName());
    }

    @Test
    void testSchemaTitleSet() {
      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "propertyName", "Property Label", "Property Description",
          null, Collections.emptySet(), Collections.emptyList(), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertEquals("Property Label", schema.getTitle());
    }

    @Test
    void testSchemaDescriptionSet() {
      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "propertyName", "Property Label", "Property Description",
          null, Collections.emptySet(), Collections.emptyList(), List.of("string"));

      Schema<?> schema = mapper.getSchemaByDataProperty();

      assertEquals("Property Description", schema.getDescription());
    }

    @Test
    void testGetNameReturnsCorrectName() {
      DataPropertyMapper mapper = new DataPropertyMapper(
          config, "myPropertyName", "Label", "Desc",
          null, Collections.emptySet(), Collections.emptyList(), List.of("string"));

      assertEquals("myPropertyName", mapper.getName());
    }
  }
}

