    25→public class TestUtil {
    26→
    27→  public static Path copyToRealFile(Class<?> cls, String resourceName) {
    28→    try {
    29→
    30→      InputStream is = Optional.ofNullable(cls.getResourceAsStream(resourceName)).orElseThrow();
    31→      Path confFile = Files.createTempFile(StringUtils.substringBeforeLast(resourceName, "."),
    32→          "." + StringUtils.substringAfterLast(resourceName, "."));
    33→      Files.copy(is, confFile, StandardCopyOption.REPLACE_EXISTING);
    34→      return confFile;
    35→    } catch (Exception e) {
    36→      throw new RuntimeException(e);
    37→    }
    38→
    39→  }
    40→
    41→  public static Path asFilePath(Class<?> cls, String resourceName) {
    42→    try {
    43→      return Paths.get(Objects.requireNonNull(cls.getResource(resourceName)).toURI());
    44→    } catch (URISyntaxException e) {
    45→      throw new RuntimeException(e);
    46→    }
    47→  }
    48→
    49→
    50→  public static DocumentContext generate(Path configPath) {
    51→    try {
    52→      YamlConfig config = load(configPath);
    53→      File apiSpecFile = config.getApiOutputDir().resolve("openapi.json").toFile();
    54→      if (apiSpecFile.delete()) {
    55→        System.out.println("Deleted existing spec file: " + apiSpecFile);
    56→      }
    57→      Asg.main(new String[]{"-c", configPath.toAbsolutePath().toString()});
    58→      assertTrue(apiSpecFile.exists(),
    59→          "No spec files generated, expected:" + apiSpecFile);
    60→      return JsonPath.parse(apiSpecFile);
    61→    } catch (IOException e) {
    62→      throw new RuntimeException(e);
    63→    }
    64→  }
    65→
    66→  private static final Map<Path, ReadContext> generatedSpecs = new HashMap<>();
    67→
    68→  public static ReadContext getGeneratedSpec(Path configPath) {
    69→    return generatedSpecs.computeIfAbsent(configPath, TestUtil::generate);
    70→  }
    71→}

