package com.grl.component.asg.configuration;

import com.fasterxml.jackson.annotation.JsonGetter;
import com.fasterxml.jackson.annotation.JsonIgnore;
import com.fasterxml.jackson.annotation.JsonMerge;
import com.fasterxml.jackson.annotation.JsonProperty;
import com.fasterxml.jackson.databind.annotation.JsonDeserialize;
import io.swagger.v3.oas.models.Components;
import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.PathItem;
import io.swagger.v3.oas.models.security.SecurityScheme;
import io.swagger.v3.oas.models.security.SecurityScheme.Type;
import jakarta.validation.constraints.Pattern;
import jakarta.validation.constraints.Size;
import java.net.URI;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import javax.annotation.Nonnull;

@SuppressWarnings("FieldMayBeFinal")
public class YamlConfig {
  public static class Templates {

    private PathItem collectionPathItem;
    private PathItem singlePathItem;

    private OpenAPI openapi = new OpenAPI();

    /**
     * OpenAPI template to use for the generated api
     *
     * @return openapi template
     */
    @JsonMerge
    public OpenAPI getOpenapi() {
      return openapi;
    }

    /**
     * PathItem template to use for the generated collection api endpoint
     * @return path item template
     */
    @JsonMerge
    public PathItem getCollectionPathItem() {
      return collectionPathItem;
    }

    /**
     * PathItem template to use for the generated single api endpoint
     * @return path item template
     */
    @JsonMerge
    public PathItem getSinglePathItem() {
      return singlePathItem;
    }

  }

  private Path outputDir;

  @Pattern(regexp = "^[a-zA-Z0-9_]+$", message = "Name must be alphanumeric with underscores only")
  private String name;

  /**
   * Openapi templates used as defaults when generating collection/single api endpoints
   */
  @JsonMerge
  private Templates templates = new Templates();


  private List<URI> ontologies = new ArrayList<>();

  private Path catalogFile;

  private String rootClass;

  private boolean enforceRequiredness;

  @Pattern(regexp = "^$|((\\{action}|\\{api|\\{model}|\\{security}|\\w+)(\\W|$))+")
  private String securitySchemeName;

  @Pattern(regexp = "^$|((\\{action}|\\{api}|\\{model}|\\w+)(\\W|$))+")
  private String defaultSecurityTemplate;

  @JsonMerge
  private Map<PathItem.HttpMethod, String> securityActionMappings = new HashMap<>();

  public String getDefaultSecurityTemplate() {
    return defaultSecurityTemplate;
  }

  public String getSecurityTemplate() {
    return securityTemplate;
  }

